import './App.css';
import "@radix-ui/themes/styles.css";
import { Theme, ThemePanel, Box, Container, Button, Flex, Text, Section} from "@radix-ui/themes";

function App() {
  return (
    <Theme accentColor="yellow" panelBackground="solid" radius="full">
      <Box style={{ background: "var(--gray-a2)", borderRadius: "var(--radius-3)" }}>
        <Container size="3">
          <Box>
            <Section size="2" />
          </Box>
        </Container>
      </Box>
    </Theme>
  );
}

export default App;
